482	                        }
483	                        src1_buf += in_tensor_ch;
484	                    }
485	                }
486	                col_counter++;
487	
488	                /* Computation is filed for every 256 columns */
489	                if (col_counter == tiling_size)
490	                {
491	                    out = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
492	                                                                 src2,
493	                                                                 dst_i32,
494	                                                                 out,
495	                                                                 out_scale,
496	                                                                 out_shift,
497	                                                                 col_counter,
498	                                                                 in_tensor_ch * ker_dim_x * ker_dim_y,
499	                                                                 out_tensor_ch,
500	                                                                 out_offset,
501	                                                                 act_min,
502	                                                                 act_max,
503	                                                                 contri_buf,
504	                                                                 tiling_size);
505	
506	                    /* counter reset */
507	                    col_counter = 0;
508	                    src1_buf = src1;
509	                }
510	            }
511	        }
512	
513	        /* check if there is left-over for compute */
514	        out = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
515	                                                     src2,
516	                                                     dst_i32,
517	                                                     out,
518	                                                     out_scale,
519	                                                     out_shift,
520	                                                     col_counter,
521	                                                     in_tensor_ch * ker_dim_x * ker_dim_y,
522	                                                     out_tensor_ch,
523	                                                     out_offset,
524	                                                     act_min,
525	                                                     act_max,
526	                                                     contri_buf,
527	                                                     tiling_size);
528	        /* next in_tensor batch offset */
529	        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
530	    }
531	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64)
532	    const uint32_t rhs_cols = ker_dim_y * ker_dim_x * in_tensor_ch;
533	    long maxvl_per_loop;
534	
535	    //--- calculate the buffer address ---
536	    const long align_byte = sizeof(long);
537	    // buffer-1
538	    int8_t *two_column_buf = (int8_t*)in_tmp_buf;
539	    two_column_buf = (int8_t*)nn_align((unsigned long)two_column_buf, align_byte);  // align the starting addresss
540	    // buffer-2
541	    long two_column_buf_size = 2 * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(*in_tensor);
542	    int32_t *contri_buf = (int32_t*)(two_column_buf + two_column_buf_size);
543	    contri_buf = (int32_t*)nn_align((unsigned long)contri_buf, align_byte);         // align the starting addresss
544	
545	    // calculate the weight contribution
546	    const int8_t *pWt = ker_weight;
547	    int32_t *pContri_buf = contri_buf;
548	    const int32_t *pBias = bias;
549	    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
550	    if (bias != NULL)
551	    {
552	        long out_tensor_ch2 = out_tensor_ch;
553	        long vl;
554	        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
555	        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
556	
557	        while (out_tensor_ch2 > 0)
558	        {
559	            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
560	            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
561	            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
562	            NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot
563	
564	            long rhs_cols2 = rhs_cols;
565	            while (rhs_cols2 >= maxvl_per_loop)
566	            {
567	                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
568	                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
569	                pWt += vl;
570	                rhs_cols2 -= vl;
571	
572	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
573	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
574	            }
575	
576	            //clean one of the dot product source
577	            long tmp_avl;
578	            tmp_avl = rhs_cols2 + 3;
579	            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
580	            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
581	            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
582	            NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot
583	
584	            // remain loop
585	            while (rhs_cols2 > 0)
586	            {
587	                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
588	                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
589	                pWt += vl;
590	                rhs_cols2 -= vl;
591	
592	                vl = (vl + 3) >> 2;
593	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
594	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
595	            }
596	
597	            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
598	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
599	
600	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
601	            NDS_VEC_VLE32_V(NDS_VEC_V1, pBias);
602	            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution
603	            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V1);    // add bias
604	            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
605	            pBias += vl;
606	            pContri_buf += vl;
607	            out_tensor_ch2--;
608	        }
609	    }
610	    else
611	    {
612	        long out_tensor_ch2 = out_tensor_ch;
613	        long vl;
614	        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
615	        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
616	
617	        while (out_tensor_ch2 > 0)
618	        {
619	            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
620	            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
621	            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
622	            NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot
623	
624	            long rhs_cols2 = rhs_cols;
625	            while (rhs_cols2 >= maxvl_per_loop)
626	            {
627	                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
628	                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
629	                pWt += vl;
630	                rhs_cols2 -= vl;
631	
632	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
633	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
634	            }
635	
636	            //clean one of the dot product source
637	            long tmp_avl;
638	            tmp_avl = rhs_cols2 + 3;
639	            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
640	            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
641	            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
642	            NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot
643	
644	            // remain loop
645	            while (rhs_cols2 > 0)
646	            {
647	                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
648	                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
649	                pWt += vl;
650	                rhs_cols2 -= vl;
651	
652	                vl = (vl + 3) >> 2;
653	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
654	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
655	            }
656	
657	            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
658	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
659	
660	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
661	            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
662	            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
663	            pContri_buf++;
664	            out_tensor_ch2--;
665	        }
666	    }
667	
668	    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
669	    {
670	        int8_t *two_column_buf2 = two_column_buf;
671	        int8_t *out = out_tensor;
672	
673	        /* This part implements the im2col function */
674	        for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
675	        {
676	            for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
677	            {
678	                for (long cur_ker_y = cur_out_y * stride_y - pad_y; cur_ker_y < cur_out_y * stride_y - pad_y + ker_dim_y; cur_ker_y++)
679	                {
680	                    for (long cur_ker_x = cur_out_x * stride_x - pad_x; cur_ker_x < cur_out_x * stride_x - pad_x + ker_dim_x; cur_ker_x++)
681	                    {
682	                        if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
683	                        {
684	                            nn_set_val_s8(two_column_buf2, -in_offset, in_tensor_ch);
685	                        }
686	                        else
687	                        {
688	                            nn_dup_s8(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, two_column_buf2, in_tensor_ch);
689	                        }
690	                        two_column_buf2 += in_tensor_ch;
691	                    }
692	                }
693	
694	                /* Computation is filed for every 2 columns */
695	                if (two_column_buf2 == (int8_t *)two_column_buf + 2 * in_tensor_ch * ker_dim_y * ker_dim_x)
696	                {
697	                    out = nn_mat_mult_kernel_s8_offset_v2(ker_weight,
698	                                                          two_column_buf,
699	                                                          out_tensor_ch,
700	                                                          out_shift,
701	                                                          out_scale,
702	                                                          in_offset,
703	                                                          out_offset,
704	                                                          act_min,
705	                                                          act_max,
706	                                                          rhs_cols,
707	                                                          contri_buf,
708	                                                          out);
709	
710	                    /* counter reset */
711	                    two_column_buf2 = (int8_t *)two_column_buf;
712	                }
713	            }
714	        }
715	
716	        /* left-over because odd number of output pixels */
717	        if (two_column_buf2 != (int8_t *)two_column_buf)
718	        {
719	            uint32_t vl;
720	            const int8_t *pWt = ker_weight;
721	            const int32_t *pOut_scale = out_scale;
722	            const int32_t *pOut_shift = out_shift;
723	            int32_t *pContri_buf = contri_buf;
724	
725	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
726	            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
727	
728	            for (long i = 0; i < out_tensor_ch; i++)
729	            {
730	                uint32_t rhs_cols2 = rhs_cols;
731	                const int8_t *pIn = (int8_t *)two_column_buf;
732	
733	                // init the accumulators
734	                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
735	                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
736	
737	                while (rhs_cols2 >= maxvl_per_loop)
738	                {
739	                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
740	                    NDS_VEC_VLE8_V(NDS_VEC_V8, pIn);
741	                    NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
742	                    rhs_cols2 -= vl;
743	                    pIn += vl;
744	                    pWt += vl;
745	
746	                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
747	                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
748	                }
749	
750	                // rest loop
751	                if (rhs_cols2 > 0)
752	                {
753	                    //clean one of the dot product source
754	                    long tmp_avl;
755	                    tmp_avl = rhs_cols2 + 3;
756	                    NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
757	                    NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
758	
759	                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
760	                    NDS_VEC_VLE8_V(NDS_VEC_V8, pIn);
761	                    NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
762	                    rhs_cols2 -= vl;
763	                    pIn += vl;
764	                    pWt += vl;
765	
766	                    vl = (vl + 3) >> 2;
767	                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
768	                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
769	                }
770	
771	                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
772	                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
773	
774	                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
775	                //add extra contribution back
776	                NDS_VEC_VLE32_V(NDS_VEC_V4, pContri_buf);
777	                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
778	
779	                //===== Quantize down =====
780	                NDS_VEC_VLE32_V(NDS_VEC_V2, pOut_shift);
781	                NDS_VEC_VLE32_V(NDS_VEC_V3, pOut_scale);
782	                NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
783	
784	                NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
785	                NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
786	                NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
787	
788	                // Add offset
789	                NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
790	
791	                // Clamp the result
792	                NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
793	                NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
794	
795	                //narrowing and store the results
796	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
797	                NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
798	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
799	                NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
800	                NDS_VEC_VSE8_V(NDS_VEC_V4, out);

